// Mechanical Orrery — a brass geared planetary solar-system model.
//
// Reference: handcrafted brass tabletop orreries (e.g. "Wanderers" brass
// orrery and steampunk brass-and-stone orreries) — a round brass base with an
// EXPOSED meshing gear train, a central sun on a column, and jewel-tone planet
// spheres mounted on curved arms that sweep out at staggered orbital radii.
//
// Showcases BOSL2 `spur_gear()` + `gear_dist()` (true involute teeth that
// manifold can't easily do) and `path_sweep()`/`arc()` for the curved arms.
//
// COLOR: every paintable piece is a top-level `label("name") <expr>;` statement
// so each region self-colors via paintByLabel. SCAD labels survive ONLY when
// each labeled statement maps 1:1 to a lazy-union AMF object — so EVERY loop is
// UNROLLED into explicit top-level statements (a `for(...) label(...)` emits N
// objects from one statement, the count mismatches, and ALL labels are
// dropped). Helper modules are fine: one invocation = one object.

include <BOSL2/std.scad>
include <BOSL2/gears.scad>

$fa = 4;
$fs = 0.5;

// ---------------------------------------------------------------------------
// Parameters
// ---------------------------------------------------------------------------
circ_pitch   = 6;      // circular pitch shared by the whole gear train
sun_teeth    = 28;     // big central drive gear
idler_teeth  = 13;     // small idler gears meshing around the sun
gear_thk     = 9;      // gear face width — tall so teeth read clearly
base_thk     = 7;      // brass base plate thickness
base_r       = 56;     // base plate radius (snug around the gear train)

// Derived gear radii / spacing.
sun_pitch_r  = (circ_pitch * sun_teeth)   / (2 * PI);
sun_tip_r    = sun_pitch_r + circ_pitch / PI;
center_dist  = gear_dist(circ_pitch=circ_pitch, teeth1=sun_teeth, teeth2=idler_teeth);

arm_w        = 4.2;    // orbit arm cross-section width (broad brass blade)
arm_h        = 2.8;    // orbit arm cross-section height
column_h     = 40;     // central column height (sun is a crown, not a flagpole)
column_r     = 5.5;

// Raised hub the gear train rides on.
hub_r   = sun_tip_r + center_dist + 7;
hub_top = base_thk + 4;          // gears sit on this surface
gear_z  = hub_top + gear_thk / 2;
column_base_z = gear_z + gear_thk / 2 - 1.5;   // overlap down into the sun gear

// ---------------------------------------------------------------------------
// Helper modules (geometry only — never labeled inside; labels are top-level).
// ---------------------------------------------------------------------------

// One idler gear at heading `a` around the sun, phased to mesh.
module idler(a) {
  translate([center_dist * cos(a), center_dist * sin(a), gear_z])
    spur_gear(circ_pitch=circ_pitch, teeth=idler_teeth, thickness=gear_thk,
              shaft_diam=0, gear_spin=180 / idler_teeth);
}

// A brass bolt-head stud at (radius r, heading a), top at z.
module bolt(r, a, z) {
  translate([r * cos(a), r * sin(a), z])
    cyl(h=2.6, d=5.2, $fn=6, chamfer2=0.8, anchor=BOTTOM);
}

// Brass axle cap pinning an idler at heading a.
module axlecap(a) {
  translate([center_dist * cos(a), center_dist * sin(a), gear_z + gear_thk / 2 - 0.5])
    cyl(h=3, d=5, rounding2=1, anchor=BOTTOM);
}

// Orbit arm: a clean circular "rainbow" arc from the column up and over to the
// planet at (orbit_r, top_z), swept with a broad rounded brass bar. Path lives
// in the X-Z plane (X = radius, Z = height); rotate stands it upright.
module orbit_arm(orbit_r, top_z, heading) {
  start_x = column_r - 1.0;
  start_z = column_base_z + 3;
  apex_z  = max(start_z, top_z) + 13;
  arc_pts = arc(n=32, points=[
    [start_x,        start_z],     // at the column
    [orbit_r * 0.5,  apex_z],      // crown of the rainbow
    [orbit_r,        top_z],       // down onto the planet
  ]);
  prof = rect([arm_w, arm_h], rounding=1.0, $fn=16);
  rotate([0, 0, heading])
    rotate([90, 0, 0])
      path_sweep(prof, arc_pts);
}

// Planet sphere at the tip of its arm.
module planet(orbit_r, sph_r, top_z, heading) {
  rotate([0, 0, heading])
    translate([orbit_r, 0, top_z + sph_r - 1.2])
      sphere(r=sph_r);
}

// ---------------------------------------------------------------------------
// BASE PLATE — brass, round, stepped rim + raised central hub. ONE statement.
// ---------------------------------------------------------------------------
label("base")
  difference() {
    union() {
      cyl(h=base_thk, r=base_r, rounding2=3, anchor=BOTTOM);              // disc
      up(base_thk - 0.5) cyl(h=4.5, r=hub_r, rounding2=1.5, anchor=BOTTOM); // hub
    }
    down(0.1) cyl(h=base_thk - 2.5, r=base_r - 10, anchor=BOTTOM);        // pocket
  }

// ---------------------------------------------------------------------------
// GEAR TRAIN — central sun gear + 3 meshing idlers (each its own statement).
// ---------------------------------------------------------------------------
label("sun_gear")
  translate([0, 0, gear_z])
    spur_gear(circ_pitch=circ_pitch, teeth=sun_teeth, thickness=gear_thk,
              shaft_diam=0, gear_spin=180 / sun_teeth);

label("idlers") idler(30);
label("idlers") idler(150);
label("idlers") idler(270);

// ---------------------------------------------------------------------------
// CENTRAL COLUMN + collar + glowing sun.
// ---------------------------------------------------------------------------
label("column")
  translate([0, 0, column_base_z])
    cyl(h=column_h, r1=column_r, r2=column_r * 0.7, rounding2=1.5, anchor=BOTTOM);

label("collar")
  translate([0, 0, column_base_z + column_h * 0.5])
    cyl(h=4, r=column_r + 2.4, chamfer=1.2, anchor=BOTTOM);

label("sun")
  translate([0, 0, column_base_z + column_h + 9])
    sphere(r=11);

// ---------------------------------------------------------------------------
// ORBIT ARMS + PLANETS — three arms 120deg apart, heights cascading outward so
// the orbits tier in 3D. Headings fan toward the camera-facing front.
//   arm tier heights: inner gear_z+10, mid +32, outer +54.
// ---------------------------------------------------------------------------
// Headings fan across the camera-facing front hemisphere (iso view looks from
// front-right) so all three planets stay clear of the column and read.
label("arms") orbit_arm(36, gear_z + 16, 165);   // inner — Mars
label("arms") orbit_arm(54, gear_z + 34, 250);   // mid   — Earth
label("arms") orbit_arm(72, gear_z + 54,  15);   // outer — Jupiter

label("mars")    planet(36,  7.5, gear_z + 16, 165);
label("earth")   planet(54,  9.0, gear_z + 34, 250);
label("jupiter") planet(72, 10.5, gear_z + 54,  15);

// Saturn-style ring around the outer (Jupiter) planet — overlaps it.
label("ring")
  rotate([0, 0, 15])
    translate([72, 0, gear_z + 54 + 10.5 - 1.2])
      rotate([70, 0, 18])
        tube(h=0.8, or=10.5 + 3.2, ir=10.5 + 1.8, $fn=56);

// ---------------------------------------------------------------------------
// Decorative brass bolt studs around the rim + idler axle caps (unrolled).
// ---------------------------------------------------------------------------
label("bolts") bolt(base_r - 5,   0, base_thk + 0.8);
label("bolts") bolt(base_r - 5,  45, base_thk + 0.8);
label("bolts") bolt(base_r - 5,  90, base_thk + 0.8);
label("bolts") bolt(base_r - 5, 135, base_thk + 0.8);
label("bolts") bolt(base_r - 5, 180, base_thk + 0.8);
label("bolts") bolt(base_r - 5, 225, base_thk + 0.8);
label("bolts") bolt(base_r - 5, 270, base_thk + 0.8);
label("bolts") bolt(base_r - 5, 315, base_thk + 0.8);

label("bolts") axlecap(30);
label("bolts") axlecap(150);
label("bolts") axlecap(270);
